// requirements.psd1 — declares Az modules the Functions runtime installs automatically
{
  "Az": "11.*"
}

# Useful profile helpers for Azure work

function azctx {
    # Quick display of current subscription and tenant
    $ctx = Get-AzContext
    Write-Host "Sub : $($ctx.Subscription.Name)" -ForegroundColor Cyan
    Write-Host "Tenant: $($ctx.Tenant.Id)" -ForegroundColor Yellow
}

function azsub {
    param([string]$Name)
    # Switch subscription by name fragment
    $sub = Get-AzSubscription | Where-Object { $_.Name -like "*$Name*" } | Select-Object -First 1
    if ($sub) { Set-AzContext -Subscription $sub.Id; azctx }
    else { Write-Error "No subscription matching '$Name'" }
}

#!/usr/bin/env pwsh
# update-az.ps1 — run weekly via Task Scheduler or cron
param(
    [string]$RequiredMinVersion = "11.0.0",
    [string]$Scope = "CurrentUser"
)

$current = (Get-InstalledModule -Name Az -ErrorAction SilentlyContinue).Version
if (-not $current) {
    Write-Host "Az not installed. Installing..."
    Install-Module Az -Scope $Scope -Force -Repository PSGallery
} else {
    $latest = (Find-Module Az -Repository PSGallery).Version
    if ([version]$latest -gt [version]$current) {
        Write-Host "Updating Az from $current to $latest"
        Update-Module Az -Scope $Scope -Force
        # Remove old versions to save disk space
        Get-InstalledModule Az -AllVersions |
            Where-Object Version -ne $latest |
            Uninstall-Module -Force
    } else {
        Write-Host "Az $current is current (latest: $latest)"
    }
}

# Verify minimum version gate
$installed = (Get-InstalledModule Az).Version
if ([version]$installed -lt [version]$RequiredMinVersion) {
    Write-Error "Az $installed does not meet minimum $RequiredMinVersion"
    exit 1
}
Write-Host "Az $installed ready."
